# features/steps/enriched_steps.py
import allure
from pytest_bdd import given, when, then, parsers


@then("the response identifies the error as an expired card")
@allure.title("Response correctly identifies error 4012 as expired card")
@allure.severity(allure.severity_level.CRITICAL)
def response_identifies_expired_card():
    with allure.step("LLM judge: does response mention card expiry?"):
        passed, reason = judge(
            "The response correctly identifies error 4012 as relating to "
            "an expired or invalid card.",
            _context["response"],
        )
        allure.attach(
            _context["response"],
            name="AI Response",
            attachment_type=allure.attachment_type.TEXT,
        )
        assert passed, f"Judge: {reason}"

# scripts/diff_living_docs.py
"""Compare Allure result JSONs between two release snapshots."""
import json, pathlib, sys

def load_results(tag: str) -> dict[str, str]:
    base = pathlib.Path(f"docs/specs/{tag}/data/test-cases")
    results = {}
    for f in base.glob("*.json"):
        tc = json.loads(f.read_text())
        results[tc["name"]] = tc["status"]   # "passed" | "failed" | "broken"
    return results

def diff(old_tag: str, new_tag: str):
    old, new = load_results(old_tag), load_results(new_tag)
    regressions, improvements = [], []
    for name in old:
        if name not in new:
            continue
        if old[name] == "passed" and new[name] != "passed":
            regressions.append((name, old[name], new[name]))
        elif old[name] != "passed" and new[name] == "passed":
            improvements.append((name, old[name], new[name]))
    return regressions, improvements

if __name__ == "__main__":
    old_tag, new_tag = sys.argv[1], sys.argv[2]
    regressions, improvements = diff(old_tag, new_tag)
    print(f"\n=== Regressions ({old_tag} -> {new_tag}) ===")
    for name, o, n in regressions:
        print(f"  FAIL  {name}  ({o} -> {n})")
    print(f"\n=== Improvements ===")
    for name, o, n in improvements:
        print(f"  PASS  {name}  ({o} -> {n})")
    if regressions:
        sys.exit(1)   # fail the CI gate

# scripts/hooks/pre_commit_prompt_check.py
"""Warn if a staged prompt file change affects linked BDD scenarios."""
import subprocess, pathlib, sys, re

def staged_prompts() -> list[str]:
    result = subprocess.run(
        ["git", "diff", "--cached", "--name-only"],
        capture_output=True, text=True
    )
    return [f for f in result.stdout.splitlines() if f.startswith("prompts/")]

def scenarios_referencing(prompt_file: str) -> list[str]:
    prompt_id = pathlib.Path(prompt_file).stem   # e.g. "payment_assistant_v2"
    pattern = re.compile(rf'@prompt:{re.escape(prompt_id)}')
    hits = []
    for feat in pathlib.Path("tests/bdd/features").rglob("*.feature"):
        if pattern.search(feat.read_text()):
            hits.append(str(feat))
    return hits

def main():
    warnings = False
    for prompt_file in staged_prompts():
        scenarios = scenarios_referencing(prompt_file)
        if scenarios:
            print(f"\n⚠  {prompt_file} is staged — linked scenarios may need re-running:")
            for s in scenarios:
                print(f"   {s}")
            warnings = True
    if warnings:
        print("\nRun: pytest tests/bdd/ -m prompt_linked --alluredir allure-results")
        print("Update living-docs before merging.")
        # Return 0 to warn, not block — use 1 to hard-block
        sys.exit(0)

main()
